#include <cmath>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* -----------------------------------------------------------------
       1. compute column means
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += data[i][j];
        mean[j] = sum / n;
    }

    /* -----------------------------------------------------------------
       2. center the data:  data[i][j] -= mean[j]
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j)
            row[j] -= mean[j];
    }

    /* -----------------------------------------------------------------
       3. compute upper‑triangular part of covariance matrix
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            double val = sum / (n - 1.0);
            cov[i][j] = val;
            cov[j][i] = val;   // symmetry
        }
    }
}
