/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate temporary buffer once
    std::vector<double> z(n, 0.0);

    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    // Main loop
    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute correlation sum
        double sum = 0.0;
        for (int i = 0; i < k; ++i)
            sum += r[k - i - 1] * y[i];

        // Update alpha
        alpha = -(r[k] + sum) / beta;

        // Update prediction coefficients via temporary buffer
        for (int i = 0; i < k; ++i)
            z[i] = y[i] + alpha * y[k - i - 1];

        // Commit new coefficients back to y
        std::memcpy(y.data(), z.data(), k * sizeof(double));

        y[k] = alpha;
    }
}
