/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    /* The loop inherently has a data dependency so it must run
       serially.  We keep the outer loop serial but we still
       remove any virtual calls and unused bounds checks by
       accessing the underlying data buffers directly. */

    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        double* Li   = L[i].data();      // pointer to row i of L
        double* xi_0 = &x[0];            // pointer to the beginning of x

        /* Unroll the inner loop by a factor of 4.  The remainder
           is handled by a simple scalar loop. */
        int j = 0;
        int lim = i - (i & 3);
        for (; j < lim; j += 4) {
            sum -= Li[j]   * xi_0[j];
            sum -= Li[j+1] * xi_0[j+1];
            sum -= Li[j+2] * xi_0[j+2];
            sum -= Li[j+3] * xi_0[j+3];
        }
        for (; j < i; ++j) {
            sum -= Li[j] * xi_0[j];
        }

        x[i] = sum / Li[i];
    }
}
