/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Cache local copies of the scalar parameters to avoid
       repeated memory loads inside the loops. */
    const double a = alpha;
    const double b = beta;

    /* Parallelise the outer loop.  Each iteration works on a
       separate row of A and B, so there are no data races. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        /* Get raw pointers to the beginning of the i‑th rows.
           Using raw pointers allows the compiler to generate
           streaming loads/stores and better loop
           optimization. */
        const double* a_row = A[i].data();
        const double* b_row = B[i].data();
        const double* x_row = x.data();          // same for all i
        double* tmp_row = tmp.data();
        double* y_row   = y.data();

        double t = 0.0;
        double y_val = 0.0;

        /* Inner loop – compute A[i][j] * x[j] and B[i][j] * x[j] */
#pragma ivdep
        for (int j = 0; j < n; ++j)
        {
            t += a_row[j] * x_row[j];
            y_val += b_row[j] * x_row[j];
        }

        /* Final combination using the gathered results */
        tmp_row[i] = t;
        y_row[i]   = a * t + b * y_val;
    }
}
