void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Helper to check Watson–Crick pair: A(0)–U(3) or C(1)–G(2)
    auto match = [](int b1, int b2) noexcept { return (b1 + b2 == 3) ? 1 : 0; };

    // We fill the DP table by increasing the length of the subsequence.
    // Each length `len` can be processed in parallel because all needed
    // sub‑problems belong to shorter lengths (< len).
    for (int len = 2; len <= n; ++len) {
        int max_i = n - len;
        #pragma omp parallel for schedule(static)
        for (int i = 0; i <= max_i; ++i) {
            int j = i + len - 1;
            int best = table[i][j - 1];
            if (table[i + 1][j] > best) best = table[i + 1][j];

            // Pair i with j if possible; otherwise treat it as a separate sub‑problem
            int cand = (i < j - 1) ?
                        (table[i + 1][j - 1] + match(seq[i], seq[j])) :
                        table[i + 1][j - 1];
            if (cand > best) best = cand;

            // Split at k
            for (int k = i + 1; k < j; ++k) {
                int sum = table[i][k] + table[k + 1][j];
                if (sum > best) best = sum;
            }
            table[i][j] = best;
        }
    }
}
