/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    // Y is zeroed once – no need to parallelise this trivial part
    for (int j = 0; j < n; ++j) y[j] = 0.0;

    /* Parallel over the rows of A. Each thread works on a private
       chunk of y to avoid false‑sharing.  A standard 2‑dimensional
       reduction is emulated by summing a local buffer into the
       global y after the parallel region.                         */
    #pragma omp parallel
    {
        // Allocate a private buffer for this thread
        std::vector<double> y_buf(n, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            tmp[i] = 0.0;
            double* rowA  = A[i].data();   // pointer to the i‑th row
            const double* xptr = x.data(); // pointer to x

            // Compute tmp[i] = rowA · x
            for (int j = 0; j < n; ++j) {
                tmp[i] += rowA[j] * xptr[j];
            }

            // Accumulate into the thread’s private y buffer
            for (int j = 0; j < n; ++j) {
                y_buf[j] += rowA[j] * tmp[i];
            }
        }

        // Merge private y buffers into the global y
        #pragma omp critical
        for (int j = 0; j < n; ++j) {
            y[j] += y_buf[j];
        }
    }
}
