/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    /* convert 2‑D std::vector to array of pointers for faster access */
    double **a = new double*[n];
    for (int i = 0; i < n; ++i) a[i] = A[i].data();

    /* LU factorisation */
    for (int i = 0; i < n; ++i) {
        /* upper triangle */
        for (int j = 0; j < i; ++j) {
            double w = a[i][j];
#pragma omp simd
            for (int k = 0; k < j; ++k) {
                w -= a[i][k] * a[k][j];
            }
            a[i][j] = w / a[j][j];
        }
        /* lower triangle (diagonal and below) */
        for (int j = i; j < n; ++j) {
            double w = a[i][j];
#pragma omp simd
            for (int k = 0; k < i; ++k) {
                w -= a[i][k] * a[k][j];
            }
            a[i][j] = w;
        }
    }

    /* Forward substitution: L * y = b */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
#pragma omp simd
        for (int j = 0; j < i; ++j) {
            w -= a[i][j] * y[j];
        }
        y[i] = w;               // lower triangle is 1.0 on the diagonal
    }

    /* Backward substitution: U * x = y */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
#pragma omp simd
        for (int j = i + 1; j < n; ++j) {
            w -= a[i][j] * x[j];
        }
        x[i] = w / a[i][i];
    }

    delete [] a;
}
