/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {

    const double inv3 = 0.3333333333333333;           // 1/3 for better precision
    double* a = A.data();                            // raw pointers for faster access
    double* b = B.data();

#pragma omp parallel
    {
        // Using a parallel for for the first update
#pragma omp for schedule(static)
        for (int t = 0; t < tsteps; ++t) {
            // First half‑step: B[i] = (A[i-1]+A[i]+A[i+1]) / 3
#pragma omp for schedule(static) nowait
#pragma clang loop simd
            for (int i = 1; i < n - 1; ++i) {
                b[i] = inv3 * (a[i - 1] + a[i] + a[i + 1]);
            }

            // Second half‑step: A[i] = (B[i-1]+B[i]+B[i+1]) / 3
#pragma omp for schedule(static) nowait
#pragma clang loop simd
            for (int i = 1; i < n - 1; ++i) {
                a[i] = inv3 * (b[i - 1] + b[i] + b[i + 1]);
            }
        }   // end of timesteps loop
    }   // end of parallel region
}
```
This implementation:

* Uses raw pointers (`double* a,b`) for fastest memory access.
* Parallelises the outer timestep loop using a single parallel region, avoiding repeated thread creation.
* Parallelises the two inner spatial loops with `#pragma omp for` and `schedule(static)` for load balance.
* Adds `nowait` to allow the second loop to start immediately after the first one finishes, avoiding an extra barrier.
* Uses `inv3` for an exact 1/3 and enables compiler auto‑vectorisation (`#pragma clang loop simd` – works with GCC as `#pragma omp simd` as well).

