void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* Parallelize over the outer dimension.  The loop is
       embarrassingly parallel because each thread works on
       a distinct set of rows i.  OpenMP automatically creates
       a thread pool that matches the number of processors
       (8 in the target environment). */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < n; ++i)
    {
        /* First scale the lower‑triangle part of C[i] by beta.
           Only the thread owning row i touches this memory. */
        double* Ci = C[i].data();
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        /* Accumulate the rank‑k update.
           We pull A[i][k] once per column k and reuse it
           for all j, reducing the number of multiplications. */
        const double* Ai = A[i].data();
        for (int k = 0; k < m; ++k)
        {
            const double aik = alpha * Ai[k];
            if (aik == 0.0) continue;           /* skip zero factors */

            /* Access all A[j][k] for j <= i.  Since A is stored
               as a vector of rows, this accesses a stride of 1
               across rows, which is cache‑friendly in the
               lower‑triangle traversal below. */
            for (int j = 0; j <= i; ++j)
                Ci[j] += aik * A[j][k];
        }
    }
}
