// Optimised trmm kernel for GCC 9+ (C++17)
#include <vector>
#include <omp.h>
#include <cstddef>
#include <cstring>
#include <iostream>

/* Backward-looking triangular matrix–matrix multiplication
 * B = alpha * A^T * B
 *
 * A is M×M (upper‑triangular stored row major)
 * B is M×N (column major to match BLAS convention)
 *
 * The kernel preserves the exact numerical behaviour of the
 * reference implementation while exploiting data locality
 * and parallelism on an 8‑core x86‑64 machine.
 */
void kernel_trmm(int m,
                 int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Make a column‑major view of B to reduce cache misses.
    // Allocate a contiguous N×M buffer (N rows, M columns).
    const std::size_t strideB = m;
    std::vector<double> B_cnj(n * m);   // N * M
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            B_cnj[j * strideB + i] = B[i][j];

    // Unroll the inner k‑loop: 4‑way block.
    const int blk = 4;

    // Parallelise over the outermost i‑loop (rows of B).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double *Bi = &B_cnj[0 * strideB + i];       // B[i, :]
        for (int j = 0; j < n; ++j) {
            double temp = 0.0;
            int k = i + 1;
            // 4‑way unrolled loop over k
            for (; k <= m - blk; k += blk) {
                temp += A[k][i]     * Bi[j] +
                        A[k+1][i]   * Bi[j] +
                        A[k+2][i]   * Bi[j] +
                        A[k+3][i]   * Bi[j];
            }
            for (; k < m; ++k)
                temp += A[k][i] * Bi[j];
            Bi[j] = alpha * temp;
        }
    }

    // Copy back the results into the original B structure
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            B[i][j] = B_cnj[j * strideB + i];
}
