                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {

    /* 1. Zero‑initialise s.  Parallel vectorisation would add a
       small overhead because we overwrite the values later anyway,
       so leave it as a simple loop. */
    for (int i = 0; i < m; ++i) s[i] = 0.0;

    /* 2. Parallel work over the outer dimension i.
       Each thread keeps a private local accumulator for s
       to avoid false sharing and atomics.  */
    std::vector<double> s_local(m, 0.0);          // one per thread
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        double* local_s = &s_local[tid * m];   // each thread gets own block
        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            /* compute q[i] and update local_s */
            double qi = 0.0;
            double ri = r[i];
            const std::vector<double> &Ai = A[i];
            for (int j = 0; j < m; ++j) {
                local_s[j] += ri * Ai[j];
                qi += Ai[j] + p[j];
            }
            q[i] = qi;
        }
    }

    /* 3. Reduce per‑thread local_s into the final s vector.
       The number of threads is small (<=8), so a simple pointwise
       summation is cheaper than an atomic update per element. */
    int num_threads = omp_get_max_threads();
    if (num_threads == 1) {
        // no parallelism: nothing to reduce
        return;
    }
    // gather the per‑thread contributions
    for (int t = 0; t < num_threads; ++t) {
        const double* const src = &s_local[t * m];
        for (int j = 0; j < m; ++j) {
            s[j] += src[j];
