    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / static_cast<double>(n);
    }

    /* ------------------------ */
    /* 2. compute column stddevs */
    /* ------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double ss = 0.0;
        double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            ss += d * d;
        }
        ss /= static_cast<double>(n);
        ss = std::sqrt(ss);
        stddev[j] = (ss <= eps) ? 1.0 : ss;
    }

    /* ------------------------ */
    /* 3. normalize data matrix  */
    /* ------------------------ */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * (1.0 / (norm * stddev[j]));
        }
    }

    /* ------------------------ */
    /* 4. compute correlation matrix */
    /* ------------------------ */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
