/*
 * QR decomposition with Modified Gram–Schmidt.
 * The function signature is preserved for the harness.
 *  - m: number of rows (A and Q)
 *  - n: number of columns (A, R, Q)
 *  - A, R, Q: stored as std::vector<std::vector<double>>
 *
 * The implementation below uses OpenMP to parallelise the
 *   * vector‑length computations (nrm)
 *   * normalisation of Q
 *   * inner update of the remaining columns (j‑loop)
 *
 * The work‑sharing directives are chosen to minimise
 *    false sharing – each thread works on a different chunk
 *    of rows or columns, so the inner arrays are not
 *    accessed concurrently by several threads.
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {

    for (int k = 0; k < n; ++k) {

        /* --- compute ||A[:,k]||² (nrm) ---------------------------------- */
        double nrm_sq = 0.0;
        #pragma omp parallel for reduction(+:nrm_sq) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm_sq += val * val;
        }

        double norm = std::sqrt(nrm_sq);
        R[k][k] = norm;

        /* --- normalise the k‑th column into Q --------------------------- */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / norm;
        }

        /* --- process remaining columns j>k ----------------------------- */
        #pragma omp parallel for schedule(static) firstprivate(k, norm)
        for (int j = k + 1; j < n; ++j) {
            double r_kj = 0.0;
            /* compute projection coefficient r_kj = Q[:,k]^T * A[:,j] */
            for (int i = 0; i < m; ++i) {
                r_kj += Q[i][k] * A[i][j];
            }
            R[k][j] = r_kj;

            /* update A[:,j] -= Q[:,k] * r_kj */
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * r_kj;
            }
        }
    }
}
