               std::vector<std::vector<double>>& A)
{
    // We work with raw pointers to each row for maximum cache efficiency.
    // The outer loop must stay serial because each row depends on the
    // results computed for the previous rows in a classical LU factorisation.
    for (int i = 0; i < n; ++i) {
        double* rowA = A[i].data();

        // Compute the lower part (j < i)
        for (int j = 0; j < i; ++j) {
            double* rowAk = A[i].data();      // alias for A[i][*]
