    for (int i = 0; i < n; ++i) {
        double* Ai = rowViews[i];

        /* Sub‑diagonal entries (i > j) */
        for (int j = 0; j < i; ++j) {
            double* Aj = rowViews[j];
            double sum = 0.0;

            /* Accumulate dot product A[i][k] * A[j][k] for k < j */
            // Inner loop is vectorised by the compiler (thanks to -O2)
            for (int k = 0; k < j; ++k) {
