    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flatA[i*n + j] = A[i][j].data();

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flatB[i*n + j] = B[i][j].data();

    /* Pre‑compute the list of indices that need to be visited.  This
     * avoids the repeated bounds checks inside the hot loops.
     */
    std::vector<int> idx;
    idx.reserve((n - 2) * (n - 2) * (n - 2));
    for (int i = 1; i < n - 1; ++i)
        for (int j = 1; j < n - 1; ++j)
            for (int k = 1; k < n - 1; ++k)
                idx.push_back((i * n + j) * n + k);

    /* Main time‑stepping loop */
    for (int t = 0; t < tsteps; ++t) {
