            const int k  = rem % n;

            double a = flatA[i*n + j][k];
            double aip = flatA[(i+1)*n + j][k];
            double aim = flatA[(i-1)*n + j][k];
            double ajp = flatA[i*n + j + 1][k];
            double ajm = flatA[i*n + j - 1][k];
