void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    // Flatten indices for contiguous storage – each row is continuous.
    const int N = n;
    const double DX = 1.0 / N;
    const double DY = 1.0 / N;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 / 2.0;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 / 2.0;
    const double e   = 1.0 + mul2;
    const double f   = d;

    const int stride = N;                 // row stride

    // Pointers to the inner storage for speed.
    double *U = new double[N * N];
    double *V = new double[N * N];
    double *P = new double[N * N];
    double *Q = new double[N * N];

    // Copy data from the 2‑D vectors into the flat arrays.
    for (int i = 0; i < N; ++i)
        for (int j = 0; j < N; ++j) {
            U[i*stride + j] = u[i][j];
            V[i*stride + j] = v[i][j];
            P[i*stride + j] = p[i][j];
            Q[i*stride + j] = q[i][j];
        }

    // Main time loop
    for (int t = 1; t <= tsteps; ++t) {

        /* ---------- first half (vertical sweep) ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N-1; ++i) {
            int idx = i*stride;

            V[0*stride + i] = 1.0;
            P[idx + 0] = 0.0;
            Q[idx + 0] = V[0*stride + i];

            for (int j = 1; j < N-1; ++j) {
                int ij = idx + j;
                P[ij] = -c / (a * P[ij-1] + b);
                Q[ij] = (-d * U[(j)*stride + (i-1)] +
                         (1.0 + 2.0*d) * U[(j)*stride + (i)] -
                         f * U[(j)*stride + (i+1)] -
                         a * Q[ij-1]) / (a * P[ij-1] + b);
            }

            V[(N-1)*stride + i] = 1.0;

            for (int j = N-2; j >= 1; --j) {
                int ij = idx + j;
                V[j*stride + i] = P[ij] * V[(j+1)*stride + i] + Q[ij];
            }
        }

        /* ---------- second half (horizontal sweep) ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N-1; ++i) {
            int idx = i*stride;

            U[idx + 0] = 1.0;
            P[idx + 0] = 0.0;
            Q[idx + 0] = U[idx + 0];

            for (int j = 1; j < N-1; ++j) {
                int ij = idx + j;
                P[ij] = -f / (d * P[ij-1] + e);
                Q[ij] = (-a * V[(i-1)*stride + j] +
                         (1.0 + 2.0*a) * V[(i)*stride + j] -
                         c * V[(i+1)*stride + j] -
                         d * Q[ij-1]) / (d * P[ij-1] + e);
            }

            U[idx + N-1] = 1.0;
            for (int j = N-2; j >= 1; --j) {
                int ij = idx + j;
                U[idx + j] = P[ij] * U[idx + j + 1] + Q[ij];
            }
        }
    }

    // Copy back results to the original 2‑D vectors
    for (int i = 0; i < N; ++i)
        for (int j = 0; j < N; ++j) {
            u[i][j] = U[i*stride + j];
            v[i][j] = V[i*stride + j];
            p[i][j] = P[i*stride + j];
            q[i][j] = Q[i*stride + j];
        }

    delete [] U;
    delete [] V;
    delete [] P;
    delete [] Q;
}
