#include <cmath>
#include <vector>
#include <omp.h>

/*
 * Optimised implementation of the Deriche filter.
 * All semantics of the original kernel are preserved.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---- pre‑compute constants -------------------------------------------------- */
    const double expA  = std::exp(-alpha);
    const double exp2A = std::exp(-2.0 * alpha);

    const float k = 1.0f - static_cast<float>(expA * (1.0 - expA) /
                     (1.0 + 2.0 * alpha * expA - exp2A));

    const float a1 = k,           a5 = k;
    const float a2 = k * static_cast<float>(expA * (alpha - 1.0));
    const float a6 = a2;
    const float a3 = k * static_cast<float>(expA * (alpha + 1.0));
    const float a7 = a3;
    const float a4 = -k * static_cast<float>(exp2A);
    const float a8 = a4;

    const float b1 = static_cast<float>(std::pow(2.0, -alpha));
    const float b2 = -static_cast<float>(exp2A);

    const float c1 = 1.0f, c2 = 1.0f;

    /* ---- row‑wise forward pass ---------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float ym1 = 0.0f;
        float ym2 = 0.0f;
        float xm1 = 0.0f;

        const float* in  = imgIn[i].data();
        float*        y1i = y1[i].data();

        for (int j = 0; j < h; ++j)
        {
            const float inij = *in++;
            *y1i++ = a1 * inij + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1   = inij;
            ym2   = ym1;
            ym1   = *(y1i - 1);
        }
    }

    /* ---- row‑wise backward pass ---------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float yp1 = 0.0f;
        float yp2 = 0.0f;
        float xp1 = 0.0f;
        float xp2 = 0.0f;

        const float* ini  = imgIn[i].data();
        float*        y2i = y2[i].data();

        for (int j = h - 1; j >= 0; --j)
        {
            const float inv = ini[j];
            y2i[j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = inv;
            yp2 = yp1;
            yp1 = y2i[j];
        }
    }

    /* ---- combine row results ----------------------------------------------- */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);

    /* ---- column‑wise forward pass -------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float tm1 = 0.0f;
        float ym1 = 0.0f;
        float ym2 = 0.0f;

        for (int i = 0; i < w; ++i)
        {
            const float outij = imgOut[i][j];
            y1[i][j] = a5 * outij + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = outij;
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* ---- column‑wise backward pass ------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float tp1 = 0.0f;
        float tp2 = 0.0f;
        float yp1 = 0.0f;
        float yp2 = 0.0f;

        for (int i = w - 1; i >= 0; --i)
        {
            const float outij = imgOut[i][j];
            y2[i][j] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = outij;
            yp2 = yp1;
            yp1 = y2[i][j];
        }
    }

    /* ---- combine final results ---------------------------------------------- */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
}
